"use client";

import { useState } from "react";

export default function Home() {
  const [file, setFile] = useState<File | null>(null);
  const [status, setStatus] = useState<string>("");
  const [notes, setNotes] = useState<string>("");
  const [loading, setLoading] = useState<boolean>(false);

  async function handleSubmit() {
    if (!file) return;

    setLoading(true);
    setNotes("");

    // Step 1: Upload
    setStatus("Uploading file...");
    const formData = new FormData();
    formData.append("file", file);

    const uploadRes = await fetch("/api/upload", {
      method: "POST",
      body: formData,
    });
    const uploadData = await uploadRes.json();
    const meetingId = uploadData.meeting.id;

    // Step 2: Transcribe
    setStatus("Transcribing audio... (this may take a minute)");
    await fetch("/api/transcribe", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ meetingId }),
    });

    // Step 3: Generate notes
    setStatus("Generating meeting notes...");
    const notesRes = await fetch("/api/notes", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ meetingId }),
    });
    const notesData = await notesRes.json();

    setNotes(notesData.meeting.notes);
    setStatus("Done!");
    setLoading(false);
  }

  return (
    <main style={{ maxWidth: 800, margin: "0 auto", padding: "2rem" }}>
      <h1>AuraMeet</h1>
      <p>Upload a Zoom recording to generate structured meeting notes.</p>

      <div style={{ margin: "2rem 0" }}>
        <input
          type="file"
          accept=".mp4,.m4a,.aiff,.mp3,.wav"
          onChange={(e) => setFile(e.target.files?.[0] || null)}
        />
        <button
          onClick={handleSubmit}
          disabled={!file || loading}
          style={{ marginLeft: "1rem", padding: "0.5rem 1rem" }}
        >
          {loading ? "Processing..." : "Generate Notes"}
        </button>
      </div>

      {status && <p><strong>{status}</strong></p>}

      {notes && (
        <div style={{ marginTop: "2rem", whiteSpace: "pre-wrap" }}>
          <h2>Meeting Notes</h2>
          <div style={{ background: "#f5f5f5", padding: "1rem", borderRadius: 8 }}>
            {notes}
          </div>
        </div>
      )}
    </main>
  );
}